  1→import path from "node:path";
  2→
  3→import { type Api, getEnvApiKey, type Model } from "@mariozechner/pi-ai";
  4→import type { MoltbotConfig } from "../config/config.js";
  5→import type { ModelProviderAuthMode, ModelProviderConfig } from "../config/types.js";
  6→import { getShellEnvAppliedKeys } from "../infra/shell-env.js";
  7→import { formatCliCommand } from "../cli/command-format.js";
  8→import {
  9→  type AuthProfileStore,
 10→  ensureAuthProfileStore,
 11→  listProfilesForProvider,
 12→  resolveApiKeyForProfile,
 13→  resolveAuthProfileOrder,
 14→  resolveAuthStorePathForDisplay,
 15→} from "./auth-profiles.js";
 16→import { normalizeProviderId } from "./model-selection.js";
 17→
 18→export { ensureAuthProfileStore, resolveAuthProfileOrder } from "./auth-profiles.js";
 19→
 20→const AWS_BEARER_ENV = "AWS_BEARER_TOKEN_BEDROCK";
 21→const AWS_ACCESS_KEY_ENV = "AWS_ACCESS_KEY_ID";
 22→const AWS_SECRET_KEY_ENV = "AWS_SECRET_ACCESS_KEY";
 23→const AWS_PROFILE_ENV = "AWS_PROFILE";
 24→
 25→function resolveProviderConfig(
 26→  cfg: MoltbotConfig | undefined,
 27→  provider: string,
 28→): ModelProviderConfig | undefined {
 29→  const providers = cfg?.models?.providers ?? {};
 30→  const direct = providers[provider] as ModelProviderConfig | undefined;
 31→  if (direct) return direct;
 32→  const normalized = normalizeProviderId(provider);
 33→  if (normalized === provider) {
 34→    const matched = Object.entries(providers).find(
 35→      ([key]) => normalizeProviderId(key) === normalized,
 36→    );
 37→    return matched?.[1] as ModelProviderConfig | undefined;
 38→  }
 39→  return (
 40→    (providers[normalized] as ModelProviderConfig | undefined) ??
 41→    (Object.entries(providers).find(([key]) => normalizeProviderId(key) === normalized)?.[1] as
 42→      | ModelProviderConfig
 43→      | undefined)
 44→  );
 45→}
 46→
 47→export function getCustomProviderApiKey(
 48→  cfg: MoltbotConfig | undefined,
 49→  provider: string,
 50→): string | undefined {
 51→  const entry = resolveProviderConfig(cfg, provider);
 52→  const key = entry?.apiKey?.trim();
 53→  return key || undefined;
 54→}
 55→
 56→function resolveProviderAuthOverride(
 57→  cfg: MoltbotConfig | undefined,
 58→  provider: string,
 59→): ModelProviderAuthMode | undefined {
 60→  const entry = resolveProviderConfig(cfg, provider);
 61→  const auth = entry?.auth;
 62→  if (auth === "api-key" || auth === "aws-sdk" || auth === "oauth" || auth === "token") {
 63→    return auth;
 64→  }
 65→  return undefined;
 66→}
 67→
 68→function resolveEnvSourceLabel(params: {
 69→  applied: Set<string>;
 70→  envVars: string[];
 71→  label: string;
 72→}): string {
 73→  const shellApplied = params.envVars.some((envVar) => params.applied.has(envVar));
 74→  const prefix = shellApplied ? "shell env: " : "env: ";
 75→  return `${prefix}${params.label}`;
 76→}
 77→
 78→export function resolveAwsSdkEnvVarName(env: NodeJS.ProcessEnv = process.env): string | undefined {
 79→  if (env[AWS_BEARER_ENV]?.trim()) return AWS_BEARER_ENV;
 80→  if (env[AWS_ACCESS_KEY_ENV]?.trim() && env[AWS_SECRET_KEY_ENV]?.trim()) {
 81→    return AWS_ACCESS_KEY_ENV;
 82→  }
 83→  if (env[AWS_PROFILE_ENV]?.trim()) return AWS_PROFILE_ENV;
 84→  return undefined;
 85→}
 86→
 87→function resolveAwsSdkAuthInfo(): { mode: "aws-sdk"; source: string } {
 88→  const applied = new Set(getShellEnvAppliedKeys());
 89→  if (process.env[AWS_BEARER_ENV]?.trim()) {
 90→    return {
 91→      mode: "aws-sdk",
 92→      source: resolveEnvSourceLabel({
 93→        applied,
 94→        envVars: [AWS_BEARER_ENV],
 95→        label: AWS_BEARER_ENV,
 96→      }),
 97→    };
 98→  }
 99→  if (process.env[AWS_ACCESS_KEY_ENV]?.trim() && process.env[AWS_SECRET_KEY_ENV]?.trim()) {
100→    return {
101→      mode: "aws-sdk",
102→      source: resolveEnvSourceLabel({
103→        applied,
104→        envVars: [AWS_ACCESS_KEY_ENV, AWS_SECRET_KEY_ENV],
105→        label: `${AWS_ACCESS_KEY_ENV} + ${AWS_SECRET_KEY_ENV}`,
106→      }),
107→    };
108→  }
109→  if (process.env[AWS_PROFILE_ENV]?.trim()) {
110→    return {
111→      mode: "aws-sdk",
112→      source: resolveEnvSourceLabel({
113→        applied,
114→        envVars: [AWS_PROFILE_ENV],
115→        label: AWS_PROFILE_ENV,
116→      }),
117→    };
118→  }
119→  return { mode: "aws-sdk", source: "aws-sdk default chain" };
120→}
121→
122→export type ResolvedProviderAuth = {
123→  apiKey?: string;
124→  profileId?: string;
125→  source: string;
126→  mode: "api-key" | "oauth" | "token" | "aws-sdk";
127→};
128→
129→export async function resolveApiKeyForProvider(params: {
130→  provider: string;
131→  cfg?: MoltbotConfig;
132→  profileId?: string;
133→  preferredProfile?: string;
134→  store?: AuthProfileStore;
135→  agentDir?: string;
136→}): Promise<ResolvedProviderAuth> {
137→  const { provider, cfg, profileId, preferredProfile } = params;
138→  const store = params.store ?? ensureAuthProfileStore(params.agentDir);
139→
140→  if (profileId) {
141→    const resolved = await resolveApiKeyForProfile({
142→      cfg,
143→      store,
144→      profileId,
145→      agentDir: params.agentDir,
146→    });
147→    if (!resolved) {
148→      throw new Error(`No credentials found for profile "${profileId}".`);
149→    }
150→    const mode = store.profiles[profileId]?.type;
151→    return {
152→      apiKey: resolved.apiKey,
153→      profileId,
154→      source: `profile:${profileId}`,
155→      mode: mode === "oauth" ? "oauth" : mode === "token" ? "token" : "api-key",
156→    };
157→  }
158→
159→  const authOverride = resolveProviderAuthOverride(cfg, provider);
160→  if (authOverride === "aws-sdk") {
161→    return resolveAwsSdkAuthInfo();
162→  }
163→
164→  const order = resolveAuthProfileOrder({
165→    cfg,
166→    store,
167→    provider,
168→    preferredProfile,
169→  });
170→  for (const candidate of order) {
171→    try {
172→      const resolved = await resolveApiKeyForProfile({
173→        cfg,
174→        store,
175→        profileId: candidate,
176→        agentDir: params.agentDir,
177→      });
178→      if (resolved) {
179→        const mode = store.profiles[candidate]?.type;
180→        return {
181→          apiKey: resolved.apiKey,
182→          profileId: candidate,
183→          source: `profile:${candidate}`,
184→          mode: mode === "oauth" ? "oauth" : mode === "token" ? "token" : "api-key",
185→        };
186→      }
187→    } catch {}
188→  }
189→
190→  const envResolved = resolveEnvApiKey(provider);
191→  if (envResolved) {
192→    return {
193→      apiKey: envResolved.apiKey,
194→      source: envResolved.source,
195→      mode: envResolved.source.includes("OAUTH_TOKEN") ? "oauth" : "api-key",
196→    };
197→  }
198→
199→  const customKey = getCustomProviderApiKey(cfg, provider);
200→  if (customKey) {
201→    return { apiKey: customKey, source: "models.json", mode: "api-key" };
202→  }
203→
204→  const normalized = normalizeProviderId(provider);
205→  if (authOverride === undefined && normalized === "amazon-bedrock") {
206→    return resolveAwsSdkAuthInfo();
207→  }
208→
209→  if (provider === "openai") {
210→    const hasCodex = listProfilesForProvider(store, "openai-codex").length > 0;
211→    if (hasCodex) {
212→      throw new Error(
213→        'No API key found for provider "openai". You are authenticated with OpenAI Codex OAuth. Use openai-codex/gpt-5.2 (ChatGPT OAuth) or set OPENAI_API_KEY for openai/gpt-5.2.',
214→      );
215→    }
216→  }
217→
218→  const authStorePath = resolveAuthStorePathForDisplay(params.agentDir);
219→  const resolvedAgentDir = path.dirname(authStorePath);
220→  throw new Error(
221→    [
222→      `No API key found for provider "${provider}".`,
223→      `Auth store: ${authStorePath} (agentDir: ${resolvedAgentDir}).`,
224→      `Configure auth for this agent (${formatCliCommand("moltbot agents add <id>")}) or copy auth-profiles.json from the main agentDir.`,
225→    ].join(" "),
226→  );
227→}
228→
229→export type EnvApiKeyResult = { apiKey: string; source: string };
230→export type ModelAuthMode = "api-key" | "oauth" | "token" | "mixed" | "aws-sdk" | "unknown";
231→
232→export function resolveEnvApiKey(provider: string): EnvApiKeyResult | null {
233→  const normalized = normalizeProviderId(provider);
234→  const applied = new Set(getShellEnvAppliedKeys());
235→  const pick = (envVar: string): EnvApiKeyResult | null => {
236→    const value = process.env[envVar]?.trim();
237→    if (!value) return null;
238→    const source = applied.has(envVar) ? `shell env: ${envVar}` : `env: ${envVar}`;
239→    return { apiKey: value, source };
240→  };
241→
242→  if (normalized === "github-copilot") {
243→    return pick("COPILOT_GITHUB_TOKEN") ?? pick("GH_TOKEN") ?? pick("GITHUB_TOKEN");
244→  }
245→
246→  if (normalized === "anthropic") {
247→    return pick("ANTHROPIC_OAUTH_TOKEN") ?? pick("ANTHROPIC_API_KEY");
248→  }
249→
250→  if (normalized === "chutes") {
251→    return pick("CHUTES_OAUTH_TOKEN") ?? pick("CHUTES_API_KEY");
252→  }
253→
254→  if (normalized === "zai") {
255→    return pick("ZAI_API_KEY") ?? pick("Z_AI_API_KEY");
256→  }
257→
258→  if (normalized === "google-vertex") {
259→    const envKey = getEnvApiKey(normalized);
260→    if (!envKey) return null;
261→    return { apiKey: envKey, source: "gcloud adc" };
262→  }
263→
264→  if (normalized === "opencode") {
265→    return pick("OPENCODE_API_KEY") ?? pick("OPENCODE_ZEN_API_KEY");
266→  }
267→
268→  if (normalized === "qwen-portal") {
269→    return pick("QWEN_OAUTH_TOKEN") ?? pick("QWEN_PORTAL_API_KEY");
270→  }
271→
272→  const envMap: Record<string, string> = {
273→    openai: "OPENAI_API_KEY",
274→    google: "GEMINI_API_KEY",
275→    groq: "GROQ_API_KEY",
276→    deepgram: "DEEPGRAM_API_KEY",
277→    cerebras: "CEREBRAS_API_KEY",
278→    xai: "XAI_API_KEY",
279→    openrouter: "OPENROUTER_API_KEY",
280→    "vercel-ai-gateway": "AI_GATEWAY_API_KEY",
281→    moonshot: "MOONSHOT_API_KEY",
282→    "kimi-code": "KIMICODE_API_KEY",
283→    minimax: "MINIMAX_API_KEY",
284→    synthetic: "SYNTHETIC_API_KEY",
285→    venice: "VENICE_API_KEY",
286→    mistral: "MISTRAL_API_KEY",
287→    opencode: "OPENCODE_API_KEY",
288→  };
289→  const envVar = envMap[normalized];
290→  if (!envVar) return null;
291→  return pick(envVar);
292→}
293→
294→export function resolveModelAuthMode(
295→  provider?: string,
296→  cfg?: MoltbotConfig,
297→  store?: AuthProfileStore,
298→): ModelAuthMode | undefined {
299→  const resolved = provider?.trim();
300→  if (!resolved) return undefined;
301→
302→  const authOverride = resolveProviderAuthOverride(cfg, resolved);
303→  if (authOverride === "aws-sdk") return "aws-sdk";
304→
305→  const authStore = store ?? ensureAuthProfileStore();
306→  const profiles = listProfilesForProvider(authStore, resolved);
307→  if (profiles.length > 0) {
308→    const modes = new Set(
309→      profiles
310→        .map((id) => authStore.profiles[id]?.type)
311→        .filter((mode): mode is "api_key" | "oauth" | "token" => Boolean(mode)),
312→    );
313→    const distinct = ["oauth", "token", "api_key"].filter((k) =>
314→      modes.has(k as "oauth" | "token" | "api_key"),
315→    );
316→    if (distinct.length >= 2) return "mixed";
317→    if (modes.has("oauth")) return "oauth";
318→    if (modes.has("token")) return "token";
319→    if (modes.has("api_key")) return "api-key";
320→  }
321→
322→  if (authOverride === undefined && normalizeProviderId(resolved) === "amazon-bedrock") {
323→    return "aws-sdk";
324→  }
325→
326→  const envKey = resolveEnvApiKey(resolved);
327→  if (envKey?.apiKey) {
328→    return envKey.source.includes("OAUTH_TOKEN") ? "oauth" : "api-key";
329→  }
330→
331→  if (getCustomProviderApiKey(cfg, resolved)) return "api-key";
332→
333→  return "unknown";
334→}
335→
336→export async function getApiKeyForModel(params: {
337→  model: Model<Api>;
338→  cfg?: MoltbotConfig;
339→  profileId?: string;
340→  preferredProfile?: string;
341→  store?: AuthProfileStore;
342→  agentDir?: string;
343→}): Promise<ResolvedProviderAuth> {
344→  return resolveApiKeyForProvider({
345→    provider: params.model.provider,
346→    cfg: params.cfg,
347→    profileId: params.profileId,
348→    preferredProfile: params.preferredProfile,
349→    store: params.store,
350→    agentDir: params.agentDir,
351→  });
352→}
353→
354→export function requireApiKey(auth: ResolvedProviderAuth, provider: string): string {
355→  const key = auth.apiKey?.trim();
356→  if (key) return key;
357→  throw new Error(`No API key resolved for provider "${provider}" (auth mode: ${auth.mode}).`);
358→}
